			"group_value":      row["group_value"],
			"user_count":       row["user_count"],
			"total_activities": row["total_activities"],
		}
	}

	return output, nil
}

func appendNonEmptyPlaceholder(placeholders []string) []string {
	return append(placeholders, "?")
