	COALESCE(SUM(CASE WHEN a.success THEN 1 ELSE 0 END), 0) AS success_count,
	COALESCE(AVG(a.duration_ms), 0) AS avg_duration
FROM user_activity a
JOIN user_profile u ON a.user_id = u.id
WHERE u.username IN (%s)
  AND a.created_at >= ?
  AND a.created_at <= ?`, userPlaceholders)

