		FROM user_profile u
		LEFT JOIN user_activity a ON u.id = a.user_id
		WHERE u.department IN (%s)
		GROUP BY u.%s
		ORDER BY u.%s`,
		groupByField,
		strings.Join(placeholders, ","),
		groupByField,
		groupByField,
	)

	var results []orm.Params
	_, err := o.Raw(sql, args...).Values(&results)
	if err != nil {
		return nil, err
	}

